#!/usr/bin/env python3
"""Apply Update v5 - PropertyProfile: rooms, contracts, remarks, docs"""
import base64, os, sqlite3

PROJECT = os.path.expanduser("~/Desktop/dream-abroad")

files = {
    "backend/models.py": "",
    "backend/schemas.py": "",
    "backend/routers/properties.py": "",
    "frontend/src/pages/PropertyProfile.tsx": "",
}

for rel_path, b64 in files.items():
    full = os.path.join(PROJECT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w") as f:
        f.write(base64.b64decode(b64).decode())
    print(f"Updated: {rel_path}")

# Create property_remarks table
db_path = os.path.join(PROJECT, "backend", "dream_abroad.db")
if os.path.exists(db_path):
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()
    cur.execute("""
    CREATE TABLE IF NOT EXISTS property_remarks (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        property_id INTEGER NOT NULL REFERENCES properties(id),
        text TEXT NOT NULL,
        created_by VARCHAR(100),
        created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )""")
    conn.commit()
    conn.close()
    print("Database: property_remarks table created")

print("\nDone! Restart backend: lsof -ti:8000 | xargs kill -9 && uvicorn main:app --reload")
